const data = $json.body;
if (!data.visitorId || !data.pageUrl) throw new Error('Missing visitorId or pageUrl');
return {
  type: 'website_visitor',
  visitorId: data.visitorId,
  pageUrl: data.pageUrl,
  referrer: data.referrer || null,
  utm: {source: data.utmSource || 'direct', medium: data.utmMedium || 'organic', campaign: data.utmCampaign, content: data.utmContent},
  ip: data.ipAddress,
  userAgent: data.userAgent,
  timestamp: new Date().toISOString()
};

const data = $json.body;
const required = ['firstName', 'lastName', 'email', 'serviceType'];
if (required.some(f => !data[f])) throw new Error('Missing required fields');
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) throw new Error('Invalid email');
return {
  type: 'form_submission',
  firstName: data.firstName.trim(),
  lastName: data.lastName.trim(),
  email: data.email.toLowerCase().trim(),
  phone: data.phone ? data.phone.replace(/\D/g, '').slice(-10) : null,
  serviceType: data.serviceType,
  formPage: data.formPage,
  timestamp: new Date().toISOString()
};

const data = $json.body;
if (!data.visitorEmail && !data.visitorPhone) throw new Error('Need email or phone');
return {
  type: 'chat_capture',
  name: data.visitorName || 'Chat Visitor',
  email: data.visitorEmail ? data.visitorEmail.toLowerCase() : null,
  phone: data.visitorPhone ? data.visitorPhone.replace(/\D/g, '').slice(-10) : null,
  messageCount: data.chatMessages?.length || 0,
  isUrgent: data.chatMessages?.some(m => /urgent|asap|emergency|rush|today/.test(m.message?.toLowerCase())) || false,
  pageUrl: data.pageUrl,
  timestamp: new Date().toISOString()
};

const data = $json.body;
const validPlatforms = ['facebook', 'instagram', 'linkedin', 'tiktok'];
if (!data.leadId || !validPlatforms.includes(data.platform?.toLowerCase())) throw new Error('Invalid platform');
if (!data.leadEmail && !data.leadPhone) throw new Error('Need email or phone');
return {
  type: 'social_lead_ads',
  leadId: data.leadId,
  name: data.leadName || 'Social Lead',
  email: data.leadEmail ? data.leadEmail.toLowerCase() : null,
  phone: data.leadPhone ? data.leadPhone.replace(/\D/g, '').slice(-10) : null,
  platform: data.platform.toLowerCase(),
  campaignId: data.campaignId,
  campaignName: data.campaignName,
  timestamp: new Date().toISOString()
};

const data = $json.body;
if (!data.referralCode) throw new Error('Missing referralCode');
if (!data.referredEmail && !data.referredPhone) throw new Error('Need email or phone');
return {
  type: 'referral_tracking',
  referralCode: data.referralCode,
  referrerEmail: data.referrerEmail ? data.referrerEmail.toLowerCase() : null,
  referrerName: data.referrerName || 'Unknown',
  email: data.referredEmail ? data.referredEmail.toLowerCase() : null,
  phone: data.referredPhone ? data.referredPhone.replace(/\D/g, '').slice(-10) : null,
  name: data.referredName || 'Referral',
  source: 'referral',
  timestamp: new Date().toISOString()
};

const data = $json.body;
if (!data.qrCodeId || !data.scannedUrl) throw new Error('Missing qrCodeId or scannedUrl');
return {
  type: 'qr_scan',
  qrCodeId: data.qrCodeId,
  scannedUrl: data.scannedUrl,
  deviceType: data.deviceType || 'unknown',
  ip: data.ipAddress,
  name: data.visitorName || null,
  email: data.visitorEmail ? data.visitorEmail.toLowerCase() : null,
  phone: data.visitorPhone ? data.visitorPhone.replace(/\D/g, '').slice(-10) : null,
  timestamp: new Date().toISOString()
};

const data = $json.body;
if (!data.callId || !data.callerId || !data.receivedPhone) throw new Error('Missing call data');
const cleanPhone = (p) => p?.replace(/\D/g, '').slice(-10) || null;
return {
  type: 'phone_call_tracking',
  callId: data.callId,
  callerId: cleanPhone(data.callerId),
  callerName: data.callerName || 'Unknown Caller',
  receivedPhone: cleanPhone(data.receivedPhone),
  duration: parseInt(data.duration) || 0,
  callTime: data.callTime || new Date().toISOString(),
  recordingUrl: data.recordingUrl || null,
  transcription: data.transcription || null,
  campaignSource: data.campaignSource || null,
  timestamp: new Date().toISOString()
};

const data = $json.body;
if (!data.scanId || !data.badgeId) throw new Error('Missing scanId or badgeId');
if (!data.attendeeEmail && !data.attendeePhone) throw new Error('Need email or phone');
return {
  type: 'event_scan',
  scanId: data.scanId,
  badgeId: data.badgeId,
  name: data.attendeeName || 'Attendee',
  email: data.attendeeEmail ? data.attendeeEmail.toLowerCase() : null,
  phone: data.attendeePhone ? data.attendeePhone.replace(/\D/g, '').slice(-10) : null,
  company: data.attendeeCompany || null,
  eventId: data.eventId,
  eventName: data.eventName,
  boothId: data.boothId,
  source: 'event',
  timestamp: new Date().toISOString()
};
